const [line] = require('fs').readFileSync(0, 'utf8').trim().split('\n');
const [numsStr, targetStr] = line.split('|');
const nums = numsStr.split(',').map(Number);
const target = Number(targetStr);
const seen = new Map();
for (let i = 0; i < nums.length; i++) {
  const need = target - nums[i];
  if (seen.has(need)) { console.log(`${seen.get(need)},${i}`); break; }
  seen.set(nums[i], i);
}
